import{a as e,i as a}from"./chunks/theme.C9g6HaIV.js";import{c as r,Q as o,j as n,m as s}from"./chunks/framework.BPKcPtvA.js";const f=JSON.parse('{"title":"Customer Finance","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/finance/customer-finance.md","filePath":"guide/admin/finance/customer-finance.md","lastUpdated":1778912818000}'),i={name:"guide/admin/finance/customer-finance.md"};function l(d,t,u,c,h,g){return o(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="customer-finance" tabindex="-1">Customer Finance <a class="header-anchor" href="#customer-finance" aria-label="Permalink to &quot;Customer Finance&quot;">​</a></h1><p><strong>Customer Finance</strong> is the cross-customer billing dashboard. It is the page you open when you want to see the financial state of every customer at once — who is overdue, who is over plan, what your outstanding total is.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p><img src="'+e+'" alt="Customer Finance dashboard" class="light-only"><img src="'+a+'" alt="Customer Finance dashboard" class="dark-only"></p><ul><li>Header with title and (in mock-data deployments) a <strong>Mock Data</strong> badge.</li><li>Filter bar — search, plan filter, status filter, plus a <strong>Export CSV</strong> dropdown.</li><li>Five summary stat cards: <ul><li><strong>Total Customers</strong></li><li><strong>Total Outstanding</strong></li><li><strong>Credit Exposure</strong></li><li><strong>Overdue Invoices</strong></li><li><strong>Over Plan</strong></li></ul></li><li>Paginated grid of customer finance cards with <strong>Load More</strong> at the bottom.</li></ul><h2 id="customer-finance-card" tabindex="-1">Customer finance card <a class="header-anchor" href="#customer-finance-card" aria-label="Permalink to &quot;Customer finance card&quot;">​</a></h2><p>Each card represents one customer.</p><ul><li><strong>Customer name</strong> — link to the customer detail page.</li><li><strong>Plan badge</strong>.</li><li><strong>Status badge</strong> — active / suspended / churned.</li><li><strong>OVERAGE badge</strong> — visible if any meter is over its included quantity. The card background turns red.</li><li>Quick stats — tenant count, user count.</li><li><strong>Usage meters</strong> — only meters with a quota (<code>includedQty &gt; 0</code>) are shown. Each meter has a bar showing billed value against the included quantity.</li><li><strong>Billing section</strong>: <ul><li><strong>Latest invoice</strong> — amount and status badge.</li><li><strong>Outstanding</strong> — total unpaid amount, in red if greater than zero.</li><li><strong>Credit balance</strong> — in green if greater than zero.</li></ul></li></ul><h2 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Filter</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Matches customer name.</td></tr><tr><td><strong>Plan</strong></td><td>All / Starter / Professional / Enterprise / any custom plan.</td></tr><tr><td><strong>Status</strong></td><td>All / Active / Suspended / Churned. Defaults to Active in non-mock mode.</td></tr></tbody></table><p>In addition, clicking a summary card narrows the grid:</p><ul><li><strong>Overdue Invoices card</strong> — shows only customers with unpaid overdue invoices.</li><li><strong>Over Plan card</strong> — shows only customers with at least one meter in overage.</li></ul><p>Both card filters are additive — you can have both on at once.</p><h2 id="export-csv" tabindex="-1">Export CSV <a class="header-anchor" href="#export-csv" aria-label="Permalink to &quot;Export CSV&quot;">​</a></h2><p>The <strong>Export CSV</strong> dropdown gives you three reports:</p><table tabindex="0"><thead><tr><th>Report</th><th>Columns</th></tr></thead><tbody><tr><td><strong>Usage Report</strong></td><td>Customer, Plan, Meter, Billed Value, Included Qty, Overage, Status.</td></tr><tr><td><strong>Accounts Receivable</strong></td><td>Customer, Invoice #, Period, Subtotal, Tax, Credits, Total, Status, Due Date, Days Overdue.</td></tr><tr><td><strong>Revenue Summary</strong></td><td>Customer, Plan, Status, Total Billed, Total Paid, Outstanding, Credit Balance, Overage Meters.</td></tr></tbody></table><p>Exports are generated client-side from the data currently in view — there is no server round-trip.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The page does not auto-refresh. Reload to see fresh data.</li><li>The card filters are independent of the toolbar filters — a customer must match both sets to appear.</li><li>&quot;Overdue Invoices&quot; counts invoices past their due date with non-zero outstanding amount.</li><li>&quot;Over Plan&quot; counts customers, not meters. A customer with three overage meters still counts as one.</li><li>The &quot;Mock Data&quot; badge means the dashboard is running with synthetic billing data. In production it should never appear.</li></ul>',19)])])}const b=r(i,[["render",l]]);export{f as __pageData,b as default};
